Rules.InvariantScript:
UpdateContext({varTab:{name:"Business Overview",Screen:BusinessOverviewScreen}});

ClearCollect(
    expensesWithDepartment,
    AddColumns(
        Expenses,
        CategoryText,
        CategoryName,
        Department,
        LookUp(User, Title = Expenses[@UserID].Value, Department)
    )
);

Set(showSignOut, false);
Set(currentUserEmail, Blank());
Set(currentUserRole, Blank());
Set(currentUserLogin, Blank());
Navigate(SignInScreen);
